  "0x7a250d5630b4cf539739df2c5dacb4c659f2488d", // Uniswap V2
  "0x68b3465833fb72a70ecdf485e0e4c7bd8665fc45", // Uniswap V3 SwapRouter02
  "0xef1c6e67703c7bd71d701e3008ed740d79d164b0", // Uniswap Universal Router
