    kind: "ERC-20",
    chainId: approval.chainId,
    chainName: approval.chainName || ("Chain " + approval.chainId),
    to: token,
    data: buildERC20RevokeCalldata(spender),
    value: "0x0",
    description: describeRevoke(approval, "ERC-20"),
