    if (a.whitelisted) return false;
    if (a.isStale === false) return false;
    // Include if: age > threshold, or unlimited, or explicitly flagged
    if (a.ageDays && a.ageDays > thresholdDays) return true;
    if (a.unlimited === true) return true;
