  if (!blast) return 0;
  if (blast.severity === "critical") return 5;
  if (blast.severity === "high") return 4;
  if (blast.severity === "medium") return 3;
  if (blast.severity === "low") return 2;
  if (blast.severity === "unknown") return 1;
